// Isso (JSX):
const element = <h1 className="titulo">Olá, React!</h1>;

// Vira isso (JavaScript puro):
const element = React.createElement(
  'h1',
  { className: 'titulo' },
  'Olá, React!'
);

const nome = 'Maria';
const idade = 25;

function App() {
  return (
    <div>
      <h1>Olá, {nome}!</h1>
      <p>Idade: {idade}</p>
      <p>Ano de nascimento: {2024 - idade}</p>
      <p>Maiúsculo: {nome.toUpperCase()}</p>
    </div>
  );
}

